mapper.select:
select c.course_id, c.course_name, c.course_code, c.subject_id, c.description, c.objectives, c.syllabus, c.cover_image, c.status, c.enrollment_start_time, c.enrollment_end_time, c.enrollment_status, c.del_flag, c.create_time, c.update_time, c.remark, s.subject_name, (select GROUP_CONCAT(u.nickname) from sys_user u where u.user_id in ( select t.user_id from edu_course_teacher ct inner join edu_teacher t on ct.teacher_id = t.teacher_id where ct.course_id = c.course_id and ct.role = 'main' ) ) as teacher_name, (select count(1) from edu_course_student cs where cs.course_id = c.course_id ) as student_count from edu_course c left join edu_subject s on c.subject_id = s.subject_id
c.del_flag = 0
AND c.course_name like concat('%', #{course.courseName}, '%')
AND c.course_code = #{course.courseCode}
AND c.subject_id = #{course.subjectId}
AND c.status = #{course.status}
order by c.create_time desc

mapper.update:
UPDATE edu_course
SET del_flag = 1, update_time = NOW()
WHERE course_id = #{courseId}
